import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface CurrentSpeed {
  download: number;
  upload: number;
  ping: number;
}

interface SpeedHistory {
  downloadSpeeds: number[];
  uploadSpeeds: number[];
}

interface NetworkSpeedData {
  currentSpeed: CurrentSpeed;
  speedHistory: SpeedHistory;
}

export default function Widget() {
  const networkSpeedData = response.data as NetworkSpeedData;
  const { currentSpeed, speedHistory } = networkSpeedData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#2C2C2E' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FF5722', mb: 1 }}>
              Net Speed Monitor
            </Typography>
            <Stack direction="row" spacing={3}>
              <Box>
                <Typography variant="body2" color="text.secondary">
                  Download
                </Typography>
                <Typography variant="h4" sx={{ color: '#F8FAFC' }}>
                  {currentSpeed.download} Mbps
                </Typography>
              </Box>
              <Box>
                <Typography variant="body2" color="text.secondary">
                  Upload
                </Typography>
                <Typography variant="h4" sx={{ color: '#F8FAFC' }}>
                  {currentSpeed.upload} Mbps
                </Typography>
              </Box>
              <Box>
                <Typography variant="body2" color="text.secondary">
                  Ping
                </Typography>
                <Typography variant="h4" sx={{ color: '#F8FAFC' }}>
                  {currentSpeed.ping} ms
                </Typography>
              </Box>
            </Stack>
          </Box>

          <LineChart
            height={120}
            series={[
              {
                data: speedHistory.downloadSpeeds,
                color: '#03A9F4',
                curve: 'natural',
                showMark: false,
              },
            ]}
            xAxis={[{ data: [0, 1, 2, 3, 4, 5], hide: true }]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
